use clap::Parser;
use std::path::PathBuf;

#[derive(Parser, Debug)]
#[command(version, about = "A file processing tool")]
struct Args {
    /// Input files to process
    #[arg(required = true)]
    files: Vec<PathBuf>,

    /// Output directory
    #[arg(short, long, default_value = "./output")]
    output: PathBuf,

    /// Processing format
    #[arg(short, long, default_value = "text")]
    format: String,

    /// Maximum number of lines to process
    #[arg(short = 'n', long)]
    max_lines: Option<usize>,

    /// Increase verbosity (-v, -vv, -vvv)
    #[arg(short, long, action = clap::ArgAction::Count)]
    verbose: u8,

    /// Suppress all output
    #[arg(short, long)]
    quiet: bool,
}

fn main() {
    let args = Args::parse();
    println!("{:?}", args);
}

use clap::{Parser, Subcommand};

#[derive(Parser)]
#[command(name = "db", about = "Database management tool")]
struct Cli {
    #[command(subcommand)]
    command: Commands,
}

#[derive(Subcommand)]
enum Commands {
    /// Run database migrations
    Migrate {
        /// Migration direction
        #[arg(default_value = "up")]
        direction: String,
    },
    /// Seed the database with test data
    Seed {
        /// Number of records to create
        #[arg(short, long, default_value_t = 100)]
        count: u32,
    },
    /// Show database status
    Status,
}

fn main() {
    let cli = Cli::parse();
    match cli.command {
        Commands::Migrate { direction } => {
            println!("Running migration: {}", direction);
        }
        Commands::Seed { count } => {
            println!("Seeding {} records", count);
        }
        Commands::Status => {
            println!("Database status: OK");
        }
    }
}

use clap::{Parser, ValueEnum};

#[derive(Clone, Debug, ValueEnum)]
enum OutputFormat {
    Json,
    Csv,
    Table,
    Pretty,
}

#[derive(Parser, Debug)]
struct Args {
    #[arg(short, long, value_enum, default_value_t = OutputFormat::Table)]
    format: OutputFormat,
}

fn main() {
    let args = Args::parse();
    println!("Format: {:?}", args.format);
}
